INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (1, 'Avahi laniger', 'Eastern woolly lemur', 'Petit lemurien indriide nocturne et arboricole a fourrure laineuse brun-gris avec le ventre plus clair. Il passe la journee en boule sur une branche ou dans une fourche d''''arbre et devient actif apres le coucher du soleil, se deplacant par bonds prudents entre quelques arbres favoris. Les couples monogames vivent avec un ou deux jeunes, forment de petits groupes familiaux et emettent des cris doux pour garder le contact. Les adultes mesurent environ 25 a 30 cm de corps pour une queue d''''une longueur similaire et pesent autour de 0,8 a 1,2 kg; aucune forte dominance de sexe n''''est decrite. L''''esperance de vie est estimee a une dizaine d''''annees a l''''etat sauvage, davantage en captivite. Habitat typique: forets et aires protegees autour de Ranomafana National Park.', 'Folivore strict: jeunes feuilles, bourgeons et fleurs consommes la nuit; fruits rarement pris.', 'VULNERABLE', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (2, 'Avahi occidentalis', 'Western woolly lemur', 'Petit lemurien indriide nocturne et arboricole a fourrure laineuse brun-gris avec le ventre plus clair. Il passe la journee en boule sur une branche ou dans une fourche d''''arbre et devient actif apres le coucher du soleil, se deplacant par bonds prudents entre quelques arbres favoris. Les couples monogames vivent avec un ou deux jeunes, forment de petits groupes familiaux et emettent des cris doux pour garder le contact. Les adultes mesurent environ 25 a 30 cm de corps pour une queue d''''une longueur similaire et pesent autour de 0,8 a 1,2 kg; aucune forte dominance de sexe n''''est decrite. L''''esperance de vie est estimee a une dizaine d''''annees a l''''etat sauvage, davantage en captivite. Habitat typique: forets et aires protegees autour de Ankarafantsika National Park.', 'Folivore strict: jeunes feuilles, bourgeons et fleurs consommes la nuit; fruits rarement pris.', 'VULNERABLE', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (3, 'Avahi peyrierasi', 'Peyrieras'' woolly lemur', 'Petit lemurien indriide nocturne et arboricole a fourrure laineuse brun-gris avec le ventre plus clair. Il passe la journee en boule sur une branche ou dans une fourche d''''arbre et devient actif apres le coucher du soleil, se deplacant par bonds prudents entre quelques arbres favoris. Les couples monogames vivent avec un ou deux jeunes, forment de petits groupes familiaux et emettent des cris doux pour garder le contact. Les adultes mesurent environ 25 a 30 cm de corps pour une queue d''''une longueur similaire et pesent autour de 0,8 a 1,2 kg; aucune forte dominance de sexe n''''est decrite. L''''esperance de vie est estimee a une dizaine d''''annees a l''''etat sauvage, davantage en captivite. Habitat typique: forets et aires protegees autour de Andohahela National Park.', 'Folivore strict: jeunes feuilles, bourgeons et fleurs consommes la nuit; fruits rarement pris.', 'VULNERABLE', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (4, 'Eulemur albifrons', 'Eulemur albifrons', 'Lemurien marron de taille moyenne au pelage generalement brun-gris avec un masque facial contraste et un ventre plus clair, le dimorphisme sexuel de coloration etant frequent. C''''est une espece cathemérale: les groupes sont actifs par episodes de jour comme de nuit, avec des pics d''''activite au lever et au coucher du soleil pour exploiter les fruits murs. Il vit en groupes mixtes de 5 a plus de 12 individus, comportant plusieurs males et femelles adultes; comme chez de nombreux lemuriens, les femelles occupent souvent la position dominante et decident des deplacements. Les adultes mesurent en moyenne 35 a 40 cm de corps pour une queue touffue de 40 a 50 cm et pesent environ 2 a 2,5 kg. En captivite, des individus depassent couramment 20 ans, l''''esperance de vie etant plus faible en nature. Habitat typique: forets et aires protegees autour de Masoala National Park.', 'Frugivore generaliste: fruits en majorite, plus feuilles, fleurs et graines; regime catheméral (activite de jour et de nuit).', 'VULNERABLE', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (5, 'Eulemur collaris', 'Eulemur collaris', 'Lemurien marron de taille moyenne au pelage generalement brun-gris avec un masque facial contraste et un ventre plus clair, le dimorphisme sexuel de coloration etant frequent. C''''est une espece cathemérale: les groupes sont actifs par episodes de jour comme de nuit, avec des pics d''''activite au lever et au coucher du soleil pour exploiter les fruits murs. Il vit en groupes mixtes de 5 a plus de 12 individus, comportant plusieurs males et femelles adultes; comme chez de nombreux lemuriens, les femelles occupent souvent la position dominante et decident des deplacements. Les adultes mesurent en moyenne 35 a 40 cm de corps pour une queue touffue de 40 a 50 cm et pesent environ 2 a 2,5 kg. En captivite, des individus depassent couramment 20 ans, l''''esperance de vie etant plus faible en nature. Habitat typique: forets et aires protegees autour de Andohahela National Park.', 'Frugivore generaliste: fruits en majorite, plus feuilles, fleurs et graines; regime catheméral (activite de jour et de nuit).', 'EN VOIE DE DISPARITION', 1);
