INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (15, 'Hapalemur aureus', 'Hapalémur doré', 'Petit lemurien bambou au pelage gris-olive ou dore avec ventre plus clair, specialise dans l''''exploitation des bambouseraies. Il est surtout crepusculaire et nocturne, concentrant son activite autour de l''''aube et du crepuscule pour se nourrir de jeunes pousses de bambou riches en fibres et parfois en composés cyanogenes. Les groupes comptent generalement de 2 a 11 individus, souvent centres sur une femelle adulte et ses petits. Les adultes mesurent autour de 25 a 35 cm de corps pour une queue de longueur comparable et pesent environ 1 a 2,5 kg selon l''''espece. Ils peuvent vivre autour de 15 ans en captivite lorsque l''''habitat et la nourriture sont assures. Habitat typique: forets et aires protegees autour de Ranomafana National Park.', 'Specialiste du bambou: jeunes pousses, feuilles et tiges, capable de tolerer le cyanure contenu dans certaines especes; complete avec quelques fruits et herbes.', 'EN DANGER CRITIQUE EXTINCTION', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (16, 'Hapalemur griseus', 'Hapalémur gris', 'Petit lemurien bambou au pelage gris-olive ou dore avec ventre plus clair, specialise dans l''''exploitation des bambouseraies. Il est surtout crepusculaire et nocturne, concentrant son activite autour de l''''aube et du crepuscule pour se nourrir de jeunes pousses de bambou riches en fibres et parfois en composés cyanogenes. Les groupes comptent generalement de 2 a 11 individus, souvent centres sur une femelle adulte et ses petits. Les adultes mesurent autour de 25 a 35 cm de corps pour une queue de longueur comparable et pesent environ 1 a 2,5 kg selon l''''espece. Ils peuvent vivre autour de 15 ans en captivite lorsque l''''habitat et la nourriture sont assures. Habitat typique: forets et aires protegees autour de Ranomafana National Park.', 'Specialiste du bambou: jeunes pousses, feuilles et tiges, capable de tolerer le cyanure contenu dans certaines especes; complete avec quelques fruits et herbes.', 'VULNERABLE', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (17, 'Hapalemur occidentalis', 'Hapalemur occidentalis', 'Petit lemurien bambou au pelage gris-olive ou dore avec ventre plus clair, specialise dans l''''exploitation des bambouseraies. Il est surtout crepusculaire et nocturne, concentrant son activite autour de l''''aube et du crepuscule pour se nourrir de jeunes pousses de bambou riches en fibres et parfois en composés cyanogenes. Les groupes comptent generalement de 2 a 11 individus, souvent centres sur une femelle adulte et ses petits. Les adultes mesurent autour de 25 a 35 cm de corps pour une queue de longueur comparable et pesent environ 1 a 2,5 kg selon l''''espece. Ils peuvent vivre autour de 15 ans en captivite lorsque l''''habitat et la nourriture sont assures. Habitat typique: forets et aires protegees autour de Ankarafantsika National Park.', 'Specialiste du bambou: jeunes pousses, feuilles et tiges, capable de tolerer le cyanure contenu dans certaines especes; complete avec quelques fruits et herbes.', 'VULNERABLE', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (18, 'Indri indri', 'Indri indri', 'Plus grand lemurien vivant, indriide robuste au pelage noir et blanc tres contraste et a la queue rudimentaire. Strictement diurne, il commence la journee par de puissants chants territoriaux audibles sur plusieurs kilometres, puis passe l''''essentiel de son temps a se deplacer et a s''''alimenter dans la canopee. Il vit en petits groupes familiaux de 2 a 6 individus, souvent un couple monogame et ses jeunes, avec une cohesion forte et des comportements d''''allogrooming. Les adultes mesurent environ 60 a 75 cm de corps pour 6 a 9,5 kg; les femelles peuvent etre legerement plus lourdes que les males. En environnement protege, ils peuvent depasser 20 ans, mais la perte d''''habitat reduit probablement cette esperance de vie a l''''etat sauvage. Habitat typique: forets et aires protegees autour de Andasibe-Mantadia National Park.', 'Régime folivore-frugivore domine par les feuilles et jeunes pousses, plus fruits, fleurs et ecorce selon la saison.', 'EN DANGER CRITIQUE EXTINCTION', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (19, 'Lemur catta', 'lémur catta', 'Lemurien emblématique a longue queue annelée noire et blanche, au dos gris et au ventre clair, tres reconnaissable. Strictement diurne et souvent terrestre, il passe beaucoup de temps au sol dans les forets seches et les paysages rocheux, pratique des bains de soleil matinaux en posture assise. Il vit en grands groupes mixtes de 6 a plus de 20 individus, avec un systeme social fortement matriarcal ou les femelles dominent les males pour l''''acces aux ressources et aux partenaires. Les adultes pesent environ 2,2 a 3,1 kg, avec un corps de 39 a 46 cm et une queue de 56 a 63 cm. L''''esperance de vie est de l''''ordre de 15 a 20 ans en nature, pouvant atteindre pres de 30 ans en captivite. Habitat typique: forets et aires protegees autour de Isalo National Park.', 'Omnivore opportuniste: fruits, feuilles, fleurs, jeunes pousses, seve et parfois insectes ou autres petits invertébrés.', 'EN VOIE DE DISPARITION', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (20, 'Lepilemur ankaranensis', 'Lepilemur ankaranensis', 'Petit lemurien sportif nocturne a grands yeux, pelage brun-gris et longue queue touffue, specialise dans les forets seches et galeries ripicoles. Strictement nocturne, il passe la journee dans des cavites d''''arbres ou des trous de rocher et sort la nuit pour se nourrir de feuilles, se deplacant par bonds entre quelques arbres favoris. L''''espece est essentiellement solitaire: chaque adulte defend un petit domaine vital, les contacts sociaux etant limites a la reproduction et aux soins aux jeunes. Les adultes mesurent environ 25 a 30 cm de corps pour une queue de longueur similaire et pesent de 0,7 a 1 kg. Les donnees suggerent une esperance de vie de l''''ordre de 8 a 12 ans a l''''etat sauvage. Habitat typique: forets et aires protegees autour de Ankarana Special Reserve.', 'Folivore nocturne: feuilles matures et jeunes feuilles, plus fleurs et ecorce; digestion lente avec longues phases de repos.', 'EN VOIE DE DISPARITION', 1);
