INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (24, 'Lepilemur ruficaudatus', 'Lepilemur ruficaudatus', 'Petit lemurien sportif nocturne a grands yeux, pelage brun-gris et longue queue touffue, specialise dans les forets seches et galeries ripicoles. Strictement nocturne, il passe la journee dans des cavites d''''arbres ou des trous de rocher et sort la nuit pour se nourrir de feuilles, se deplacant par bonds entre quelques arbres favoris. L''''espece est essentiellement solitaire: chaque adulte defend un petit domaine vital, les contacts sociaux etant limites a la reproduction et aux soins aux jeunes. Les adultes mesurent environ 25 a 30 cm de corps pour une queue de longueur similaire et pesent de 0,7 a 1 kg. Les donnees suggerent une esperance de vie de l''''ordre de 8 a 12 ans a l''''etat sauvage. Habitat typique: forets et aires protegees autour de Kirindy Forest.', 'Folivore nocturne: feuilles matures et jeunes feuilles, plus fleurs et ecorce; digestion lente avec longues phases de repos.', 'EN DANGER CRITIQUE EXTINCTION', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (25, 'Lepilemur tymerlachsoni', 'Lepilemur tymerlachsoni', 'Petit lemurien sportif nocturne a grands yeux, pelage brun-gris et longue queue touffue, specialise dans les forets seches et galeries ripicoles. Strictement nocturne, il passe la journee dans des cavites d''''arbres ou des trous de rocher et sort la nuit pour se nourrir de feuilles, se deplacant par bonds entre quelques arbres favoris. L''''espece est essentiellement solitaire: chaque adulte defend un petit domaine vital, les contacts sociaux etant limites a la reproduction et aux soins aux jeunes. Les adultes mesurent environ 25 a 30 cm de corps pour une queue de longueur similaire et pesent de 0,7 a 1 kg. Les donnees suggerent une esperance de vie de l''''ordre de 8 a 12 ans a l''''etat sauvage. Habitat typique: forets et aires protegees autour de Lokobe National Park.', 'Folivore nocturne: feuilles matures et jeunes feuilles, plus fleurs et ecorce; digestion lente avec longues phases de repos.', 'EN DANGER CRITIQUE EXTINCTION', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (26, 'Prolemur simus', 'Grand Hapalémur', 'Petit lemurien bambou au pelage gris-olive ou dore avec ventre plus clair, specialise dans l''''exploitation des bambouseraies. Il est surtout crepusculaire et nocturne, concentrant son activite autour de l''''aube et du crepuscule pour se nourrir de jeunes pousses de bambou riches en fibres et parfois en composés cyanogenes. Les groupes comptent generalement de 2 a 11 individus, souvent centres sur une femelle adulte et ses petits. Les adultes mesurent autour de 25 a 35 cm de corps pour une queue de longueur comparable et pesent environ 1 a 2,5 kg selon l''''espece. Ils peuvent vivre autour de 15 ans en captivite lorsque l''''habitat et la nourriture sont assures. Habitat typique: forets et aires protegees autour de Ranomafana National Park.', 'Specialiste du bambou: jeunes pousses, feuilles et tiges, capable de tolerer le cyanure contenu dans certaines especes; complete avec quelques fruits et herbes.', 'EN DANGER CRITIQUE EXTINCTION', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (27, 'Propithecus candidus', 'Silky sifaka', 'Sifaka de taille moyenne ou grande au pelage dense generalement clair (blanc, creme ou brun) avec des zones plus sombres selon l''''espece, se deplacant en position verticale par grands bonds entre les troncs. Strictement diurne et arboricole, il passe la majeure partie de la journee a se deplacer dans la canopee a la recherche de feuilles, jeunes pousses et fruits, et effectue parfois ses fameux sauts en danse au sol. Les groupes sociaux comptent en general 3 a 10 individus avec plusieurs adultes; la dominance des femelles sur les males est bien documentee dans plusieurs especes de sifakas. Les adultes mesurent environ 45 a 55 cm de corps pour une queue de longueur comparable et pesent de 3 a 6,5 kg selon l''''espece. Des etudes de long terme montrent que certains individus peuvent depasser 20 a 25 ans, voire 30 ans, surtout dans des conditions protegees. Habitat typique: forets et aires protegees autour de Marojejy National Park.', 'Principalement folivore (feuilles, jeunes pousses) avec une part importante de fruits et de fleurs; consomme aussi graines et ecorce.', 'EN DANGER CRITIQUE EXTINCTION', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (28, 'Propithecus coquereli', 'Coquerel''s sifaka', 'Sifaka de taille moyenne ou grande au pelage dense generalement clair (blanc, creme ou brun) avec des zones plus sombres selon l''''espece, se deplacant en position verticale par grands bonds entre les troncs. Strictement diurne et arboricole, il passe la majeure partie de la journee a se deplacer dans la canopee a la recherche de feuilles, jeunes pousses et fruits, et effectue parfois ses fameux sauts en danse au sol. Les groupes sociaux comptent en general 3 a 10 individus avec plusieurs adultes; la dominance des femelles sur les males est bien documentee dans plusieurs especes de sifakas. Les adultes mesurent environ 45 a 55 cm de corps pour une queue de longueur comparable et pesent de 3 a 6,5 kg selon l''''espece. Des etudes de long terme montrent que certains individus peuvent depasser 20 a 25 ans, voire 30 ans, surtout dans des conditions protegees. Habitat typique: forets et aires protegees autour de Ankarafantsika National Park.', 'Principalement folivore (feuilles, jeunes pousses) avec une part importante de fruits et de fleurs; consomme aussi graines et ecorce.', 'EN DANGER CRITIQUE EXTINCTION', 1);
