INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (33, 'Propithecus verreauxi', 'Verreaux''s sifaka', 'Sifaka de taille moyenne ou grande au pelage dense generalement clair (blanc, creme ou brun) avec des zones plus sombres selon l''''espece, se deplacant en position verticale par grands bonds entre les troncs. Strictement diurne et arboricole, il passe la majeure partie de la journee a se deplacer dans la canopee a la recherche de feuilles, jeunes pousses et fruits, et effectue parfois ses fameux sauts en danse au sol. Les groupes sociaux comptent en general 3 a 10 individus avec plusieurs adultes; la dominance des femelles sur les males est bien documentee dans plusieurs especes de sifakas. Les adultes mesurent environ 45 a 55 cm de corps pour une queue de longueur comparable et pesent de 3 a 6,5 kg selon l''''espece. Des etudes de long terme montrent que certains individus peuvent depasser 20 a 25 ans, voire 30 ans, surtout dans des conditions protegees. Habitat typique: forets et aires protegees autour de Beza Mahafaly Special Reserve.', 'Principalement folivore (feuilles, jeunes pousses) avec une part importante de fruits et de fleurs; consomme aussi graines et ecorce.', 'EN DANGER CRITIQUE EXTINCTION', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (34, 'Varecia rubra', 'Vari roux', 'Grand lemurien ruffed (varika) au pelage epais et bicolore, rouge et noir ou noir et blanc selon l''''espece, avec une large collerette de fourrure autour de la tete. Principalement diurne mais pouvant presenter une activite crepusculaire marquee, il se deplace dans les hautes branches a la recherche de gros fruits juteux. Il vit en communautes fission-fusion ou plusieurs femelles parentes partagent un territoire riche en arbres fruitiers, utilisant des nids foliacés pour elever les petits. Les adultes mesurent environ 50 a 60 cm de corps pour une queue touffue de 50 a 65 cm et pesent de 3 a 4,5 kg. Des donnees de captivite indiquent une esperance de vie pouvant atteindre ou depasser 30 ans, probablement plus faible en nature. Habitat typique: forets et aires protegees autour de Masoala National Park.', 'Fortement frugivore (gros fruits juteux), mais consomme aussi nectar, fleurs et feuilles; role cle dans la dispersion des grosses graines.', 'EN DANGER CRITIQUE EXTINCTION', 1);
INSERT INTO lemur (id, nom_scientifique, nom_commun, description, alimentation, iucn_status, est_protege) VALUES (35, 'Varecia variegata', 'black-and-white ruffed lemur', 'Grand lemurien ruffed (varika) au pelage epais et bicolore, rouge et noir ou noir et blanc selon l''''espece, avec une large collerette de fourrure autour de la tete. Principalement diurne mais pouvant presenter une activite crepusculaire marquee, il se deplace dans les hautes branches a la recherche de gros fruits juteux. Il vit en communautes fission-fusion ou plusieurs femelles parentes partagent un territoire riche en arbres fruitiers, utilisant des nids foliacés pour elever les petits. Les adultes mesurent environ 50 a 60 cm de corps pour une queue touffue de 50 a 65 cm et pesent de 3 a 4,5 kg. Des donnees de captivite indiquent une esperance de vie pouvant atteindre ou depasser 30 ans, probablement plus faible en nature. Habitat typique: forets et aires protegees autour de Andasibe-Mantadia National Park.', 'Fortement frugivore (gros fruits juteux), mais consomme aussi nectar, fleurs et feuilles; role cle dans la dispersion des grosses graines.', 'EN DANGER CRITIQUE EXTINCTION', 1);-- Lemur-habitation links
